create table dirkspzm32.edi_vda4987_article (
    document_id                varchar2(32 char) not null enable,
    ipig_id                    varchar2(32 char) not null enable,
    article_id                 varchar2(32 char) not null enable,
    pos                        number(4, 0) not null enable,
    article_number             varchar2(22 char),
    item_id1                   varchar2(35 char),
    item_type_id_code1         varchar2(3 char),
    item_id2                   varchar2(35 char),
    item_type_id_code2         varchar2(3 char),
    item_id3                   varchar2(35 char),
    item_type_id_code3         varchar2(3 char),
    item_id4                   varchar2(35 char),
    item_type_id_code4         varchar2(3 char),
    item_id5                   varchar2(35 char),
    item_type_id_code5         varchar2(3 char),
    usage_code                 varchar2(17 char),
    article_desc               varchar2(40 char),
    despatched_qty             number(10, 0),
    measurement_unit           varchar2(3 char),
    act_despatched_qty         number(10, 0),
    act_despatched_qty_unit    varchar2(3 char),
    origin_country             varchar2(3 char),
    duty_regime_type_code      varchar2(1 char),
    delivery_note_number       number(8, 0),
    line_no_in_delivery_note   number(3, 0),
    delivery_note_date         date,
    purchase_order_number      varchar2(12 char),
    invoice_number             varchar2(35 char),
    order_no_wholesaler        varchar2(70 char),
    order_no_cwh_wholesaler    varchar2(70 char),
    line_no_cwh_wholesaler     varchar2(6 char),
    order_no_cwh               varchar2(70 char),
    line_no_cwh                varchar2(6 char),
    supplier_duns_number       number(9, 0),
    seller_id                  varchar2(35 char),
    seller_address_desc        varchar2(35 char),
    seller_name1               varchar2(35 char),
    seller_name2               varchar2(35 char),
    seller_street1             varchar2(35 char),
    seller_street2             varchar2(35 char),
    seller_city                varchar2(35 char),
    seller_country_sub         varchar2(9 char),
    seller_postal_code         varchar2(17 char),
    seller_country_id          varchar2(3 char),
    warehouse_call_off_number  varchar2(15 char),
    line_no_warehouse_call_off varchar2(6 char),
    hazard_id_code             varchar2(7 char),
    undg_danger_good_id        number(4, 0),
    dg_desc_code               varchar2(17 char),
    dg_ft1                     varchar2(256 char),
    dg_ft2                     varchar2(256 char),
    dg_ft3                     varchar2(256 char),
    dg_ft4                     varchar2(256 char),
    dg_ft5                     varchar2(256 char),
    dg_lang_code               varchar2(3 char),
    dg_exc_desc_code           varchar2(17 char),
    dg_exc_ft1                 varchar2(256 char),
    dg_exc_ft2                 varchar2(256 char),
    dg_exc_ft3                 varchar2(256 char),
    dg_exc_ft4                 varchar2(256 char),
    dg_exc_ft5                 varchar2(256 char),
    dg_exc_lang_code           varchar2(3 char),
    unloading_point            varchar2(5 char),
    internal_place_of_use      varchar2(14 char),
    internal_forward_address   varchar2(7 char)
);

alter table dirkspzm32.edi_vda4987_article
    add constraint pk_edi_vda4987_article primary key ( article_id,
                                                        pos )
        using index enable;


